[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/lib/logger.ts","content":"import { mkdir, appendFile } from 'node:fs/promises';
import path from 'node:path';

const baseDir = path.resolve(process.cwd(), 'data');
const logPath = path.join(baseDir, 'logs.jsonl');

export async function logEvent(event: Record<string, unknown>) {
  await mkdir(baseDir, { recursive: true });
  const line = JSON.stringify({ ts: new Date().toISOString(), ...event }) + '\n';
  await appendFile(logPath, line, 'utf8');
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/lib/policy.ts","content":"import { readFile } from 'node:fs/promises';
import path from 'node:path';

export type Policy = {
  allowedShells: string[];
  blockedSubstrings: string[];
  allow: string[];
};

export async function loadPolicy(): Promise<Policy> {
  const p = path.resolve(process.cwd(), 'config', 'policy.json');
  const raw = await readFile(p, 'utf8');
  return JSON.parse(raw) as Policy;
}

export function isAllowedCommand(cmd: string, policy: Policy): { ok: boolean; reason?: string } {
  const c = cmd.trim();
  if (!c) return { ok: false, reason: 'empty' };

  for (const bad of policy.blockedSubstrings ?? []) {
    if (bad && c.toLowerCase().includes(bad.toLowerCase())) {
      return { ok: false, reason: `blocked_substring:${bad}` };
    }
  }

  const allow = policy.allow ?? [];
  const ok = allow.some((a) => {
    const needle = a.trim();
    if (!needle) return false;
    // prefix match (simple)
    return c.toLowerCase().startsWith(needle.toLowerCase());
  });

  if (!ok) return { ok: false, reason: 'not_in_allowlist' };
  return { ok: true };
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/lib/exec.ts","content":"import { spawn } from 'node:child_process';
import type { Policy } from './policy.js';
import { isAllowedCommand } from './policy.js';

export type ExecResult = {
  ok: boolean;
  exitCode: number | null;
  stdout: string;
  stderr: string;
  blocked?: boolean;
  reason?: string;
};

export async function execPowershell(command: string, policy: Policy): Promise<ExecResult> {
  const verdict = isAllowedCommand(command, policy);
  if (!verdict.ok) {
    return { ok: false, exitCode: null, stdout: '', stderr: '', blocked: true, reason: verdict.reason };
  }

  return await new Promise<ExecResult>((resolve) => {
    const ps = spawn('powershell.exe', ['-NoProfile', '-NonInteractive', '-ExecutionPolicy', 'Bypass', '-Command', command], {
      windowsHide: true
    });

    let stdout = '';
    let stderr = '';

    ps.stdout.setEncoding('utf8');
    ps.stderr.setEncoding('utf8');

    ps.stdout.on('data', (d) => (stdout += d));
    ps.stderr.on('data', (d) => (stderr += d));

    ps.on('close', (code) => {
      resolve({ ok: code === 0, exitCode: code, stdout, stderr });
    });

    ps.on('error', (err) => {
      resolve({ ok: false, exitCode: null, stdout, stderr: (stderr + String(err)).trim() });
    });
  });
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/api/schema.ts","content":"import { z } from 'zod';

export const ExecRequestSchema = z.object({
  command: z.string().min(1).max(4000)
});

export const ExecResponseSchema = z.object({
  ok: z.boolean(),
  exitCode: z.number().nullable(),
  stdout: z.string(),
  stderr: z.string(),
  blocked: z.boolean().optional(),
  reason: z.string().optional()
});

export type ExecRequest = z.infer<typeof ExecRequestSchema>;
export type ExecResponse = z.infer<typeof ExecResponseSchema>;
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/api/auth.ts","content":"import type { Request, Response, NextFunction } from 'express';
import { mustEnv } from '../lib/env.js';

export function authMiddleware(req: Request, res: Response, next: NextFunction) {
  const token = mustEnv('FAW_AGENT_TOKEN');
  const got = String(req.headers['x-faw-token'] ?? '');
  if (!got || got !== token) return res.status(401).json({ error: 'unauthorized' });
  return next();
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/api/server.ts","content":"import express from 'express';
import { ExecRequestSchema } from './schema.js';
import { authMiddleware } from './auth.js';
import { loadPolicy } from '../lib/policy.js';
import { execPowershell } from '../lib/exec.js';
import { logEvent } from '../lib/logger.js';

export type ServerOptions = {
  port: number;
};

export async function startServer(opts: ServerOptions) {
  const app = express();
  app.use(express.json({ limit: '1mb' }));

  app.get('/health', (_req, res) => res.json({ ok: true }));

  app.post('/exec', authMiddleware, async (req, res) => {
    const parsed = ExecRequestSchema.safeParse(req.body);
    if (!parsed.success) return res.status(400).json({ error: 'bad_request', issues: parsed.error.issues });

    const policy = await loadPolicy();
    const { command } = parsed.data;

    const result = await execPowershell(command, policy);

    await logEvent({
      type: 'exec',
      command,
      ok: result.ok,
      exitCode: result.exitCode,
      blocked: result.blocked ?? false,
      reason: result.reason ?? null
    });

    return res.json(result);
  });

  app.listen(opts.port, '127.0.0.1', () => {
    // eslint-disable-next-line no-console
    console.log(`[FAW] Win Terminal Agent listening on http://127.0.0.1:${opts.port}`);
  });
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/cli/repl.ts","content":"import readline from 'node:readline/promises';
import { stdin, stdout } from 'node:process';

export async function startRepl(send: (cmd: string) => Promise<{ ok: boolean; stdout: string; stderr: string; blocked?: boolean; reason?: string; exitCode: number | null }>) {
  const rl = readline.createInterface({ input: stdin, output: stdout });
  stdout.write('FAW CLI (type "exit" to quit)\n');

  while (true) {
    const line = (await rl.question('> ')).trim();
    if (!line) continue;
    if (line === 'exit' || line === 'quit') break;

    try {
      const r = await send(line);
      if (r.blocked) {
        stdout.write(`[BLOCKED] ${r.reason ?? 'policy'}\n`);
        continue;
      }
      if (r.stdout) stdout.write(r.stdout + (r.stdout.endsWith('\n') ? '' : '\n'));
      if (r.stderr) stdout.write(r.stderr + (r.stderr.endsWith('\n') ? '' : '\n'));
      if (!r.stdout && !r.stderr) stdout.write(`(exitCode=${r.exitCode})\n`);
    } catch (e) {
      stdout.write(String(e) + '\n');
    }
  }

  await rl.close();
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/cli/client.ts","content":"import { mustEnv } from '../lib/env.js';

export type ExecResponse = {
  ok: boolean;
  exitCode: number | null;
  stdout: string;
  stderr: string;
  blocked?: boolean;
  reason?: string;
};

export async function sendExec(command: string): Promise<ExecResponse> {
  const baseUrl = (process.env.FAW_AGENT_URL ?? 'http://127.0.0.1:7331').replace(/\/$/, '');
  const token = mustEnv('FAW_AGENT_TOKEN');

  const r = await fetch(`${baseUrl}/exec`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      'x-faw-token': token
    },
    body: JSON.stringify({ command })
  });

  if (!r.ok) {
    const text = await r.text().catch(() => '');
    throw new Error(`HTTP ${r.status}: ${text}`);
  }

  return (await r.json()) as ExecResponse;
}
"}[/FWP_ACTION]

[FWP_ACTION]{"type":"cs_write_file","path":"win-terminal-agent/src/index.ts","content":"import { startServer } from './api/server.js';
import { startRepl } from './cli/repl.js';
import { sendExec } from './cli/client.js';

const port = Number(process.env.FAW_AGENT_PORT ?? 7331);

await startServer({ port });

// Start a local CLI REPL that talks to the local server.
await startRepl(async (cmd) => {
  return await sendExec(cmd);
});
"}[/FWP_ACTION]

